class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

def simulate_character_stream(words_to_insert, character_stream):
    trie = Trie()
    for word in words_to_insert:
        trie.insert(word)

    print(f"Trie'ye eklenen kelimeler: {words_to_insert}")
    print(f"İşlenen karakter akışı: '{character_stream}'")
    print("-" * 30)

    current_prefix = ""
    for char in character_stream:
        current_prefix += char
        print(f"Gelen karakter: '{char}' -> Mevcut ön ek: '{current_prefix}'")

        is_word = trie.search(current_prefix)
        starts_with_prefix = trie.starts_with(current_prefix)

        if is_word:
            print(f"  -> KELİME: '{current_prefix}' Trie'da tam bir kelime olarak bulunuyor.")
        if starts_with_prefix:
            print(f"  -> BAŞLANGIÇ: '{current_prefix}' ile başlayan kelime(ler) var.")
        else:
            print(f"  -> '{current_prefix}' ile başlayan herhangi bir kelime yok.")
        print("-" * 20)

if __name__ == "__main__":
    dictionary_words = ["apple", "app", "apricot", "banana", "band", "apply", "bat"]

    print("--- Örnek 1: 'apple' kelimesinin akışı ---")
    simulate_character_stream(dictionary_words, "apple")

    print("\n" + "=" * 50 + "\n")

    print("--- Örnek 2: 'bad' kelimesinin akışı ---")
    simulate_character_stream(dictionary_words, "bad")

    print("\n" + "=" * 50 + "\n")

    print("--- Örnek 3: 'application' kelimesinin akışı ---")
    simulate_character_stream(dictionary_words, "application")
